import{_ as a,C as r,o as s,c as i,j as t,a as o,E as c,ag as d}from"./chunks/framework.HG0H2VLS.js";const f=JSON.parse('{"title":"AutoAnswers","description":"","frontmatter":{},"headers":[],"relativePath":"cc-patterns/auto-answers.md","filePath":"cc-patterns/auto-answers.md"}'),l={name:"cc-patterns/auto-answers.md"};function u(p,e,h,g,m,b){const n=r("ComponentDemo");return s(),i("div",null,[e[0]||(e[0]=t("hr",null,null,-1)),e[1]||(e[1]=t("h2",{id:"title-autoanswers",tabindex:"-1"},[o("title: AutoAnswers "),t("a",{class:"header-anchor",href:"#title-autoanswers","aria-label":'Permalink to "title: AutoAnswers"'},"​")],-1)),e[2]||(e[2]=t("h1",{id:"autoanswers",tabindex:"-1"},[o("AutoAnswers "),t("a",{class:"header-anchor",href:"#autoanswers","aria-label":'Permalink to "AutoAnswers"'},"​")],-1)),c(n,{src:"/demos/src/cc/patterns/AutoAnswers/AutoAnswers.html"}),e[3]||(e[3]=d('<h2 id="variant-×-device-×-state-matrix" tabindex="-1">Variant × Device × State Matrix <a class="header-anchor" href="#variant-×-device-×-state-matrix" aria-label="Permalink to &quot;Variant × Device × State Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State (modifier)</th><th>Theme</th><th>Header</th><th>Body</th><th>Footer / extra</th><th>Mobile delta</th></tr></thead><tbody><tr><td><code>--processing</code></td><td>info</td><td><strong>spinner</strong> (replaces sparkles) + <strong>shimmer gradient</strong> title</td><td>status text only</td><td>—</td><td>type 16→14; padding 24→16</td></tr><tr><td><code>--suggested</code></td><td>info</td><td>sparkles + title + &quot;Awaiting Feedback&quot; pill</td><td>full answer</td><td>3 action buttons</td><td>header stacks (column); pill below title; type 16→14; pill 14→12; buttons → sm (h32, px12, 12px) + stack</td></tr><tr><td><code>--no-answer</code></td><td>neutral</td><td>sparkles + title</td><td>single paragraph (tracking -0.3125px)</td><td>—</td><td>type 16→14; padding 24→16; paragraph line-height → leading-sm</td></tr><tr><td><code>--complete</code></td><td>success</td><td>sparkles + title</td><td>full answer</td><td>circle-check + &quot;marked as helpful&quot;</td><td>type 16→14; padding 24→16</td></tr><tr><td><code>--partial</code></td><td>warning</td><td>sparkles + title</td><td>full answer</td><td>thumbs-up + &quot;…helpful, further assistance required&quot;</td><td>type 16→14; padding 24→16</td></tr><tr><td><code>--inadequate</code></td><td>neutral</td><td>sparkles + title</td><td>full answer</td><td>thumbs-down + &quot;marked as not helpful&quot;</td><td>type 16→14; padding 24→16</td></tr></tbody></table><p>Interactive states (Pure CSS): action buttons <code>:hover</code> (brightness 0.96), <code>:active</code> (0.92), <code>:focus-visible</code> (brand outline). JS: SuggestedAnswer&#39;s three buttons resolve the card to a terminal marked state (Complete/Partial/Inadequate) — single-shot, no undo (Reset in demo only).</p><p><strong>ProcessingAnswer</strong> (Figma 2802:6343): a <code>loader-circle</code> spinner sits in the header heading <strong>in place of</strong> the sparkles icon while loading; the sparkles returns in every loaded state (it&#39;s only authored in non-processing headers). The body row is the status text only. Animations (all CSS, halted by <code>prefers-reduced-motion: reduce</code>): the spinner spins (<code>cc-auto-answer-spin</code> 1s) and the &quot;AI Assistant is thinking…&quot; title runs a left→right shimmer — a brighter <code>#2dc0df</code> band sweeping across the <code>--ai-surface-info</code> base via animated <code>background-position</code> + text clip (<code>cc-auto-answer-shimmer</code> 2.4s).</p><p><strong>Responsive = container-query based.</strong> The root <code>.cc-auto-answer</code> is the query container (<code>container-type: inline-size; container-name: cc-auto-answer</code>); the inner <code>.cc-auto-answer__card</code> and its descendants read it via <code>@container cc-auto-answer (max-width: 767px)</code>. The MD breakpoint (768px) is measured against the CONTAINER width, not the viewport, so the card adapts to whatever column it&#39;s dropped into. Container split is mandatory: an element with <code>container-type</code> cannot query itself, so the queried nodes must be descendants of the container (never the same element). See <code>feedback_container_self_query_trap</code>. Below MD the header switches to <code>flex-direction: column</code> (icon+title row above, &quot;Awaiting Feedback&quot; pill below — Figma 2802:6351, node 2789:5172) and the action buttons drop to the <strong>sm</strong> size (<code>min-height: --ai-spacing-7</code> 32px, <code>padding: 0 --ai-spacing-4</code>, <code>font-size: --ai-font-fluid-xxs</code> 12px — Figma <code>button/sm</code>) while also stacking. The title also drops to <code>--ai-font-fixed-xs</code> (14px) below MD (per NoAnswer mobile 2802:6340; applied globally — note SuggestedAnswer mobile shows 16px in Figma, standardised to 14px per design direction), and the NoAnswer paragraph tightens to <code>--ai-leading-sm</code>. Demo wraps ALL variants in one resizable frame (<code>resize: horizontal</code>) + width presets so the whole set transitions together, without resizing the viewport.</p><h2 id="token-gaps-normalisations-user-decision-normalise-to-nearest-token" tabindex="-1">Token Gaps &amp; Normalisations (user decision: normalise to nearest token) <a class="header-anchor" href="#token-gaps-normalisations-user-decision-normalise-to-nearest-token" aria-label="Permalink to &quot;Token Gaps &amp; Normalisations (user decision: normalise to nearest token)&quot;">​</a></h2><p>Figma authored the variants with drifting raw values; all normalised:</p><ul><li><strong>Outer card radius:</strong> <code>10px</code> (Complete/Inadequate) → <code>--ai-radius-lg</code> (16px), the value used by the other 4 states.</li><li><strong>Inner body radius:</strong> <code>10px</code> (Suggested/NoAnswer) → <code>--ai-radius-md</code> (8px).</li><li><strong>Inner body padding:</strong> <code>18px</code> (Complete/NoAnswer) → <code>--ai-spacing-6</code> (24px desktop) / <code>--ai-spacing-5</code> (16px mobile).</li><li><strong>Inadequate/Partial outer padding:</strong> <code>26px</code> → <code>--ai-spacing-6</code> (24px).</li><li><strong>NoAnswer outer gap:</strong> <code>10px</code> → <code>--ai-spacing-5</code> (16px).</li><li><strong>Code snippet font-size:</strong> <code>15px</code> → <code>--ai-font-fixed-xs</code> (14px) — matches the mobile value Figma already used.</li><li><strong>&quot;Awaiting Feedback&quot; pill bg:</strong> <code>rgba(153,200,209,0.5)</code> (= border-info @ 50%) → <code>color-mix(in srgb, var(--ai-border-info) 50%, transparent)</code>.</li><li><strong>Processing gradient stop <code>#2dc0df</code>:</strong> no semantic token; <strong>user-approved</strong> as a documented raw value in <code>--gradient</code> title.</li></ul><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th></tr></thead><tbody><tr><td>Variant frame (query container)</td><td><code>.cc-auto-answer</code> + <code>.cc-auto-answer--&lt;state&gt;</code></td></tr><tr><td>Card surface (visuals)</td><td><code>.cc-auto-answer__card</code></td></tr><tr><td>Header row</td><td><code>.cc-auto-answer__header</code></td></tr><tr><td>Icon + title group</td><td><code>.cc-auto-answer__heading</code></td></tr><tr><td><code>Icon/24px/Sparkles</code> (20px)</td><td><code>.cc-auto-answer__icon</code> (Lucide <code>sparkles</code>)</td></tr><tr><td>Title text</td><td><code>.cc-auto-answer__title</code> (<code>--gradient</code> for Processing)</td></tr><tr><td>&quot;Awaiting Feedback&quot; chip</td><td><code>.cc-auto-answer__pill</code></td></tr><tr><td>White inner box</td><td><code>.cc-auto-answer__body</code></td></tr><tr><td>Lead / closing paragraph</td><td><code>.cc-auto-answer__text</code></td></tr><tr><td>Numbered list</td><td><code>.cc-auto-answer__list</code> (<code>&lt;ol&gt;</code>)</td></tr><tr><td>Code snippet</td><td><code>.cc-auto-answer__code</code> (<code>&lt;code&gt;</code>)</td></tr><tr><td>Action button row</td><td><code>.cc-auto-answer__actions</code></td></tr><tr><td>Action button</td><td><code>.cc-auto-answer__action</code> + <code>--positive</code> / <code>--caution</code> / <code>--negative</code></td></tr><tr><td>Status footer</td><td><code>.cc-auto-answer__status</code></td></tr><tr><td>Footer icon (CircleCheck / ThumbUp / ThumbDown)</td><td><code>.cc-auto-answer__status-icon</code></td></tr><tr><td>Footer text</td><td><code>.cc-auto-answer__status-text</code></td></tr><tr><td>Spinner (in header, processing only)</td><td><code>.cc-auto-answer__spinner</code> (Lucide <code>loader-circle</code>)</td></tr><tr><td>Processing status row</td><td><code>.cc-auto-answer__processing</code></td></tr><tr><td>Processing status text</td><td><code>.cc-auto-answer__processing-text</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2>',11)),e[4]||(e[4]=t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"Figma"),t("th",null,"CSS variable"),t("th",null,"Role")])]),t("tbody",null,[t("tr",null,[t("td",null,"surface/{info,success,warning,neutral}-soft"),t("td",null,[t("code",null,"--ai-surface-*-soft")]),t("td",null,"card bg per state")]),t("tr",null,[t("td",{"info,success,warning,neutral":""},"border/"),t("td",null,[t("code",null,"--ai-border-*")]),t("td",null,"card border per state")]),t("tr",null,[t("td",{"info,success,warning,neutral":""},"text/"),t("td",null,[t("code",null,"--ai-text-*"),o(" ("),t("code",null,"--cc-aa-accent"),o(")")]),t("td",null,"title + icon + status")]),t("tr",null,[t("td",null,"surface/primary"),t("td",null,[t("code",null,"--ai-surface-primary")]),t("td",null,"inner body bg")]),t("tr",null,[t("td",null,"border/secondary"),t("td",null,[t("code",null,"--ai-border-secondary")]),t("td",null,"inner body border")]),t("tr",null,[t("td",null,"surface/secondary"),t("td",null,[t("code",null,"--ai-surface-secondary")]),t("td",null,"code snippet bg")]),t("tr",null,[t("td",null,"text/primary, text/secondary"),t("td",null,[t("code",null,"--ai-text-primary"),o(", "),t("code",null,"--ai-text-secondary")]),t("td",null,"body / code text")]),t("tr",null,[t("td",null,"surface/success, btn-primary-text, btn-primary-border"),t("td",null,[o("action "),t("code",null,"--positive")]),t("td",null,"solid success button")]),t("tr",null,[t("td",null,"surface/warning-soft + border/warning + text/warning"),t("td",null,[o("action "),t("code",null,"--caution")]),t("td",null,"soft warning button")]),t("tr",null,[t("td",null,"surface/error-soft + border/error + text/error"),t("td",null,[o("action "),t("code",null,"--negative")]),t("td",null,"soft error button")]),t("tr",null,[t("td",null,"radius/lg, radius/md, radius/sm, radius/full"),t("td",null,[t("code",null,"--ai-radius-*")]),t("td",null,"card / body / code / pill")]),t("tr",null,[t("td",null,"spacing 1/3/4/5/6/8"),t("td",null,[t("code",null,"--ai-spacing-*")]),t("td",null,"gaps, padding, button height (8 = 40px)")]),t("tr",null,[t("td",null,"font/title, font/body"),t("td",null,[t("code",null,"--ai-font-title"),o(", "),t("code",null,"--ai-font-body")]),t("td",null,"text vs buttons")]),t("tr",null,[t("td",null,"fixed-sm/fixed-xs/fixed-xxs, fluid-xs"),t("td",null,[t("code",null,"--ai-font-*")]),t("td",null,"type ramp (desktop→mobile)")]),t("tr",null,[t("td",null,"leading md/sm/xs"),t("td",null,[t("code",null,"--ai-leading-*")]),t("td",null,"line heights")]),t("tr",null,[t("td",null,"icon 20px / 16px"),t("td",null,[t("code",null,"--ai-icon-size-md"),o(" / "),t("code",null,"--ai-icon-size-sm")]),t("td",null,"header+footer / button icons")])])],-1)),e[5]||(e[5]=d('<h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Font family:</strong> Figma binds <code>--ai-font-title</code> to ALL text (titles, body, list, code, status) and <code>--ai-font-body</code> only to the buttons. Both resolve to Inter in this system, so there is no visual difference — tokens used exactly as authored.</li><li><strong>Action buttons are NOT Button-component variants</strong> (user decision: scope locally). They form a status-button family: positive = solid success, caution = soft warning, negative = soft error. Hover uses a <code>filter: brightness</code> (no new colour tokens); focus-visible uses the standard brand outline.</li><li><strong>Spinner colour</strong> (<code>--ai-surface-brand</code>) is a chosen info-theme accent — the Figma spinner asset&#39;s fill is not exposed in <code>get_design_context</code>.</li><li><strong>Width:</strong> Figma frames are 960px (desktop) / 360–407px (mobile); these are layout-frame widths, not a component constraint — the card is fluid (<code>width:100%</code>) and the demo container caps it at 900px.</li><li><strong>Letter-spacing</strong> (<code>-0.1504px</code> status, <code>-0.3125px</code> processing) kept as raw px (optical typographic value — allowed exception).</li><li>Lucide name mapping: Sparkles → <code>sparkles</code>, CircleCheck → <code>circle-check</code>, ThumbUp → <code>thumbs-up</code>, ThumbDown → <code>thumbs-down</code>, Spinner → <code>loader-circle</code>.</li></ul>',2))])}const x=a(l,[["render",u]]);export{f as __pageData,x as default};
